mapper.select:
SELECT * FROM ( SELECT innerQ.*, ROWNUM rn FROM ( SELECT p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.VIEW_COUNT , p.IMAGE_URL , COUNT(rv.REVIEW_ID) AS REVIEW_COUNT FROM PLACE p LEFT JOIN REVIEW rv ON p.PLACE_ID = rv.PLACE_ID WHERE (p.NAME LIKE '%'||#{keyword}||'%' OR p.ADDRESS LIKE '%'||#{keyword}||'%')
AND p.PLACE_TYPE = #{type}
GROUP BY p.PLACE_ID, p.PLACE_TYPE, p.NAME, p.ADDRESS, p.VIEW_COUNT, p.IMAGE_URL
ORDER BY p.PLACE_ID DESC
ORDER BY p.VIEW_COUNT DESC
) innerQ WHERE ROWNUM <= #{endRow} ) WHERE rn > #{startRow}
